#include <bits/stdc++.h>
#define int long long
using namespace std;
int qpow (int a, int b, int p) {
	int res = 1;
	while (b) {
		if (b & 1) {
			res = res * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return res;
}
int BSGS (int a, int b, int p) {
	a %= p;
	b %= p;
	int m = ceil (sqrt (p));
	int t = b;
	unordered_map <int, int> mp;
	for (int j = 0; j < m; j++) {
		mp[t] = j;
		t = t * a % p;
	}
	int mi = qpow (a, m, p);
	t = 1;
	for (int i = 1; i <= m; i++) {
		t = t * mi % p;
		if (mp.count (t)) {
			return i * m - mp[t];
		}
	}
	return -1;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	int m, k;
	cin >> m >> k;
	int ans = BSGS (k, 1, m);
	if (ans == -1 || __gcd (k, m) != 1) {
		cout << "Let's go Blue Javs!";
	} else {
		cout << ans;
	}
	return 0;
}
